# Utilities module - enums and helper functions
# Provides value types used across modules

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4
    BLACK = 5

enum ShapeType:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3

struct Point:
    """Value type for coordinates"""
    x: float
    y: float

    def __init__(self, x_coord: float, y_coord: float):
        self.x = x_coord
        self.y = y_coord

    def distance_squared_to(self, other: Point) -> float:
        dx = self.x - other.x
        dy = self.y - other.y
        return dx * dx + dy * dy

def format_color(color: Color) -> str:
    if color == Color.RED:
        return "Red"
    elif color == Color.GREEN:
        return "Green"
    elif color == Color.BLUE:
        return "Blue"
    elif color == Color.YELLOW:
        return "Yellow"
    else:
        return "Black"

def color_to_int(color: Color) -> int:
    if color == Color.RED:
        return 1
    elif color == Color.GREEN:
        return 2
    elif color == Color.BLUE:
        return 3
    elif color == Color.YELLOW:
        return 4
    else:
        return 5

def shape_type_to_int(st: ShapeType) -> int:
    if st == ShapeType.CIRCLE:
        return 1
    elif st == ShapeType.RECTANGLE:
        return 2
    else:
        return 3

