# Shapes module - class hierarchy
# Uses enums and struct from utils.spy
from utils import Color, ShapeType, Point, format_color

# Abstract base class
@abstract
class Shape:
    """Base class for all shapes - abstract"""
    color: Color
    shape_type: ShapeType

    def __init__(self, color_value: Color, shape_type_value: ShapeType):
        self.color = color_value
        self.shape_type = shape_type_value

    @abstract
    def get_name(self) -> str:
        ...

    @virtual
    def get_description(self) -> str:
        return "A shape"

    @virtual
    def area(self) -> float:
        return 0.0

# Concrete implementation
class Circle(Shape):
    """Circle inherits from base class"""
    radius: float
    center: Point

    def __init__(self, r: float, c: Point, col: Color):
        super().__init__(col, ShapeType.CIRCLE)
        self.radius = r
        self.center = c

    @override
    def get_name(self) -> str:
        return "Circle"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_description(self) -> str:
        return f"A {format_color(self.color)} circle with radius {self.radius}"

    def draw(self) -> str:
        return f"Drawing circle at ({self.center.x}, {self.center.y})"

# Rectangle inherits from Shape
class Rectangle(Shape):
    """Rectangle with width and height"""
    width: float
    height: float
    top_left: Point

    def __init__(self, w: float, h: float, position: Point, col: Color):
        super().__init__(col, ShapeType.RECTANGLE)
        self.width = w
        self.height = h
        self.top_left = position

    @override
    def get_name(self) -> str:
        return "Rectangle"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def get_description(self) -> str:
        return f"A {format_color(self.color)} rectangle"

    def draw(self) -> str:
        return f"Drawing {self.width}x{self.height} rectangle"
